1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const CURSED_SURCHARGE_RATE = 0.5;
4	const HIGH_ENCHANTMENT_RATE = 0.3;
5	const HIGH_ENCHANTMENT_THRESHOLD = 5;
6	const LOYALTY_DISCOUNT_RATE = 0.2;
7	const LOYALTY_YEARS_THRESHOLD = 2;
8	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
9	
10	const BASE_PREMIUM: Record<string, number> = {
11	  sword: 100,
12	  amulet: 60,
13	  staff: 80,
14	  potion: 40,
15	  rune: 25,
16	  moonstone: 25,
17	};
18	
19	const INSURANCE_VALUE_MULTIPLIER = 10;
20	
21	const CLAIM_DEDUCTIBLE = 100;
22	const CAP_MULTIPLIER = 2;
23	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
24	const HIGH_ENCHANTMENT_CLAIM_DAMAGE_RATE = 0.5;
25	
26	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
27	const COMPONENT_BLOCK_SIZE = 3;
28	const COMPONENT_BLOCK_PRICE = 60;
29	
30	interface Item {
31	  type: string;
32	  cursed?: boolean;
33	  enchantment?: number;
34	}
35	
36	interface QuoteStep {
37	  op: "quote";
38	  items: Item[];
39	}
40	
41	interface ClaimStep {
42	  op: "claim";
43	  policy: number;
44	  incident: { cause: string; damages: { type: string; amount: number }[] };
45	}
46	
47	type Step = QuoteStep | ClaimStep;
48	
49	interface Customer {
50	  yearsWithMHPCO: number;
51	}
52	
53	interface Scenario {
54	  customer: Customer;
55	  steps: Step[];
56	}
57	
58	function computeClaim(step: ClaimStep, scenario: Scenario): { payout: number; remainingCap: number } {
59	  const policyStep = scenario.steps[step.policy] as QuoteStep;
60	  const insuranceSum = (BASE_PREMIUM[policyStep.items[0].type] ?? 0) * INSURANCE_VALUE_MULTIPLIER;
61	  const cap = insuranceSum * CAP_MULTIPLIER;
62	  const damageAmount = step.incident.damages[0].amount;
63	  const insuredItem = policyStep.items[0];
64	  const effectiveDamage =
65	    (insuredItem.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD
66	      ? damageAmount * HIGH_ENCHANTMENT_CLAIM_DAMAGE_RATE
67	      : damageAmount;
68	  const payout = effectiveDamage - CLAIM_DEDUCTIBLE;
69	  const remainingCap = cap - payout;
70	  return { payout, remainingCap };
71	}
72	
73	function computeBasePremium(items: Item[]): number {
74	  const countsByType: Record<string, number> = {};
75	  for (const item of items) {
76	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
77	  }
78	  let basePremium = 0;
79	  for (const [type, count] of Object.entries(countsByType)) {
80	    if (COMPONENT_TYPES.has(type) && count === COMPONENT_BLOCK_SIZE) {
81	      basePremium += COMPONENT_BLOCK_PRICE;
82	    } else {
83	      const perItem = BASE_PREMIUM[type] ?? 0;
84	      basePremium += perItem * count;
85	    }
86	  }
87	  return basePremium;
88	}
89	
90	function computeItemSurcharges(items: Item[]): number {
91	  let surcharges = 0;
92	  for (const item of items) {
93	    const itemBase = BASE_PREMIUM[item.type] ?? 0;
94	    if (item.cursed) {
95	      surcharges += itemBase * CURSED_SURCHARGE_RATE;
96	    }
97	    if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
98	      surcharges += itemBase * HIGH_ENCHANTMENT_RATE;
99	    }
100	  }
101	  return surcharges;
102	}
103	
104	function computeQuote(
105	  step: QuoteStep,
106	  stepIndex: number,
107	  customer: Customer,
108	): { premium: number } {
109	  const basePremium = computeBasePremium(step.items);
110	  const itemSurcharges = computeItemSurcharges(step.items);
111	  const firstInsurance = basePremium * FIRST_INSURANCE_RATE;
112	  const loyaltyDiscount =
113	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
114	      ? basePremium * LOYALTY_DISCOUNT_RATE
115	      : 0;
116	  const isFollowUpQuote = stepIndex >= 1;
117	  const followUpDiscount = isFollowUpQuote ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
118	  const rawPremium = basePremium + itemSurcharges + firstInsurance - loyaltyDiscount - followUpDiscount + PROCESSING_FEE;
119	  const premium = Math.ceil(rawPremium);
120	  return { premium };
121	}
122	
123	export function runScenario(input: unknown): unknown {
124	  const scenario = input as Scenario;
125	  const results = scenario.steps.map((step, stepIndex) =>
126	    step.op === "claim" ? computeClaim(step, scenario) : computeQuote(step, stepIndex, scenario.customer),
127	  );
128	  return { results };
129	}
